// WebGPU compat test #11 — aether's elementwise kernels under monster:
//   WGSL_SWIGLU  out[i] = silu(gate[i]) * up[i]
//   WGSL_ADD     out[i] = a[i] + b[i]          (residual add)
//   WGSL_ADD_BIAS values[i] += bias[i % width] (qwen q/k/v proj bias broadcast)
//   WGSL_SCALE   x[i] *= scalar                (embed scale)
// All copied VERBATIM from open-source/aether/dist-browser/sovereign-shaders.js.
// Four compute dispatches, golden-diffed monster vs the Deno real-navigator.gpu
// oracle. Output quantized to 1e-4 (silu's exp diverges sub-ULP across backends).
//
// Inline pure-JS encoders; every const is single-declarator (monster gap).

function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0; x = Math.abs(x);
  let e = Math.floor(Math.log2(x)); let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; } if (m >= 2) { m /= 2; e += 1; }
  const bits = ((sign << 31) | ((e + 127) << 23) | Math.round((m - 1) * Math.pow(2, 23))) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
function bytesToF32(b0, b1, b2, b3) {
  const bits = ((b0) | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  const sign = (bits >>> 31) & 1 ? -1 : 1;
  const exp = (bits >>> 23) & 0xff;
  const mant = bits & 0x7fffff;
  if (exp === 0) return sign * mant * Math.pow(2, -149);
  if (exp === 255) return mant ? NaN : sign * Infinity;
  return sign * (1 + mant / Math.pow(2, 23)) * Math.pow(2, exp - 127);
}
function u32bytes(v) { return [v & 0xff, (v >>> 8) & 0xff, (v >>> 16) & 0xff, (v >>> 24) & 0xff]; }
function q4(v) { const s = v < 0 ? -1 : 1; return s * Math.round(Math.abs(v) * 1e4) / 1e4; }

const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();

const N = 96; // > 64 workgroup → exercises >1 workgroup dispatch
function gateVal(i) { return ((i % 9) - 4) * 0.25; }  // -1..1
function upVal(i)   { return ((i % 5) - 2) * 0.5; }    // -1..1
function aVal(i)    { return ((i % 7) - 3) * 0.25; }
function bVal(i)    { return ((i % 3) - 1) * 0.5; }
const WIDTH = 8;
function biasVal(i) { return ((i % WIDTH) - 4) * 0.125; } // per-column bias
const SCALAR = 1.5; // half-exact

function bytesOf(fn, n) {
  let b = [];
  for (let i = 0; i < n; i++) b = b.concat(f32bytes(fn(i)));
  return new Uint8Array(b);
}
function mkStorageWritable(n) {
  return device.createBuffer({ size: n * 4, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST | GPUBufferUsage.COPY_SRC });
}
function mkStorageRead(n) {
  return device.createBuffer({ size: n * 4, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
}
async function readN(buf, n) {
  const rb = device.createBuffer({ size: n * 4, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
  const enc = device.createCommandEncoder();
  enc.copyBufferToBuffer(buf, 0, rb, 0, n * 4);
  device.queue.submit([enc.finish()]);
  await rb.mapAsync(GPUMapMode.READ);
  const px = new Uint8Array(rb.getMappedRange());
  let r = [];
  for (let i = 0; i < n; i++) { const o = i * 4; r = r.concat([bytesToF32(px[o], px[o + 1], px[o + 2], px[o + 3])]); }
  rb.unmap();
  return r;
}
function dispatchN(pipeline, bindGroup, n) {
  const enc = device.createCommandEncoder();
  const pass = enc.beginComputePass();
  pass.setPipeline(pipeline);
  pass.setBindGroup(0, bindGroup);
  pass.dispatchWorkgroups(Math.ceil(n / 64), 1, 1);
  pass.end();
  device.queue.submit([enc.finish()]);
}

// ── SWIGLU ──
const WGSL_SWIGLU = `
struct N { n: u32 };
@group(0) @binding(0) var<storage, read> gate: array<f32>;
@group(0) @binding(1) var<storage, read> up: array<f32>;
@group(0) @binding(2) var<storage, read_write> out: array<f32>;
@group(0) @binding(3) var<uniform> d: N;
@compute @workgroup_size(64,1,1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
  let i = gid.x; if (i >= d.n) { return; }
  let z = gate[i];
  out[i] = (z / (1.0 + exp(-z))) * up[i];
}
`;
{
  const gateBuf = mkStorageRead(N); device.queue.writeBuffer(gateBuf, 0, bytesOf(gateVal, N));
  const upBuf = mkStorageRead(N); device.queue.writeBuffer(upBuf, 0, bytesOf(upVal, N));
  const oBuf = mkStorageWritable(N);
  const nBuf = device.createBuffer({ size: 4, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
  device.queue.writeBuffer(nBuf, 0, new Uint8Array(u32bytes(N)));
  const sm = device.createShaderModule({ code: WGSL_SWIGLU });
  const pl = device.createComputePipeline({ layout: 'auto', compute: { module: sm, entryPoint: 'main' } });
  const bg = device.createBindGroup({ layout: pl.getBindGroupLayout(0), entries: [
    { binding: 0, resource: { buffer: gateBuf } }, { binding: 1, resource: { buffer: upBuf } },
    { binding: 2, resource: { buffer: oBuf } }, { binding: 3, resource: { buffer: nBuf } }] });
  dispatchN(pl, bg, N);
  const gpu = await readN(oBuf, N);
  let cpu = [];
  for (let i = 0; i < N; i++) { const z = gateVal(i); cpu = cpu.concat([(z / (1 + Math.exp(-z))) * upVal(i)]); }
  out.swigluGpu = [q4(gpu[0]), q4(gpu[33]), q4(gpu[64]), q4(gpu[95])];
  out.swigluCpu = [q4(cpu[0]), q4(cpu[33]), q4(cpu[64]), q4(cpu[95])];
  let sg = 0; for (let i = 0; i < N; i++) sg += gpu[i];
  let sc = 0; for (let i = 0; i < N; i++) sc += cpu[i];
  out.swigluSumGpu = q4(sg); out.swigluSumCpu = q4(sc);
}

// ── ADD ──
const WGSL_ADD = `
struct N { n: u32 };
@group(0) @binding(0) var<storage, read> a: array<f32>;
@group(0) @binding(1) var<storage, read> b: array<f32>;
@group(0) @binding(2) var<storage, read_write> out: array<f32>;
@group(0) @binding(3) var<uniform> d: N;
@compute @workgroup_size(64,1,1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
  let i = gid.x; if (i >= d.n) { return; }
  out[i] = a[i] + b[i];
}
`;
{
  const aBuf = mkStorageRead(N); device.queue.writeBuffer(aBuf, 0, bytesOf(aVal, N));
  const bBuf = mkStorageRead(N); device.queue.writeBuffer(bBuf, 0, bytesOf(bVal, N));
  const oBuf = mkStorageWritable(N);
  const nBuf = device.createBuffer({ size: 4, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
  device.queue.writeBuffer(nBuf, 0, new Uint8Array(u32bytes(N)));
  const sm = device.createShaderModule({ code: WGSL_ADD });
  const pl = device.createComputePipeline({ layout: 'auto', compute: { module: sm, entryPoint: 'main' } });
  const bg = device.createBindGroup({ layout: pl.getBindGroupLayout(0), entries: [
    { binding: 0, resource: { buffer: aBuf } }, { binding: 1, resource: { buffer: bBuf } },
    { binding: 2, resource: { buffer: oBuf } }, { binding: 3, resource: { buffer: nBuf } }] });
  dispatchN(pl, bg, N);
  const gpu = await readN(oBuf, N);
  let cpu = [];
  for (let i = 0; i < N; i++) cpu = cpu.concat([aVal(i) + bVal(i)]);
  out.addGpu = [q4(gpu[0]), q4(gpu[50]), q4(gpu[95])];
  out.addCpu = [q4(cpu[0]), q4(cpu[50]), q4(cpu[95])];
}

// ── ADD_BIAS (broadcast bias[i % width]) ──
const WGSL_ADD_BIAS = `
struct BiasDims { total: u32, width: u32 };
@group(0) @binding(0) var<storage, read_write> values: array<f32>;
@group(0) @binding(1) var<storage, read> bias: array<f32>;
@group(0) @binding(2) var<uniform> d: BiasDims;
@compute @workgroup_size(64,1,1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
  let i = gid.x; if (i >= d.total) { return; }
  values[i] = values[i] + bias[i % d.width];
}
`;
{
  const vBuf = mkStorageWritable(N); device.queue.writeBuffer(vBuf, 0, bytesOf(aVal, N));
  const biasBuf = mkStorageRead(WIDTH); device.queue.writeBuffer(biasBuf, 0, bytesOf(biasVal, WIDTH));
  const dBuf = device.createBuffer({ size: 8, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
  device.queue.writeBuffer(dBuf, 0, new Uint8Array(u32bytes(N).concat(u32bytes(WIDTH))));
  const sm = device.createShaderModule({ code: WGSL_ADD_BIAS });
  const pl = device.createComputePipeline({ layout: 'auto', compute: { module: sm, entryPoint: 'main' } });
  const bg = device.createBindGroup({ layout: pl.getBindGroupLayout(0), entries: [
    { binding: 0, resource: { buffer: vBuf } }, { binding: 1, resource: { buffer: biasBuf } },
    { binding: 2, resource: { buffer: dBuf } }] });
  dispatchN(pl, bg, N);
  const gpu = await readN(vBuf, N);
  let cpu = [];
  for (let i = 0; i < N; i++) cpu = cpu.concat([aVal(i) + biasVal(i % WIDTH)]);
  out.biasGpu = [q4(gpu[0]), q4(gpu[7]), q4(gpu[8]), q4(gpu[95])];
  out.biasCpu = [q4(cpu[0]), q4(cpu[7]), q4(cpu[8]), q4(cpu[95])];
}

// ── SCALE (in place by scalar) ──
const WGSL_SCALE = `
struct S { n: u32, scalar: f32 };
@group(0) @binding(0) var<storage, read_write> x: array<f32>;
@group(0) @binding(1) var<uniform> d: S;
@compute @workgroup_size(64,1,1)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
  let i = gid.x; if (i >= d.n) { return; }
  x[i] = x[i] * d.scalar;
}
`;
{
  const xBuf = mkStorageWritable(N); device.queue.writeBuffer(xBuf, 0, bytesOf(aVal, N));
  const dBuf = device.createBuffer({ size: 8, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
  device.queue.writeBuffer(dBuf, 0, new Uint8Array(u32bytes(N).concat(f32bytes(SCALAR))));
  const sm = device.createShaderModule({ code: WGSL_SCALE });
  const pl = device.createComputePipeline({ layout: 'auto', compute: { module: sm, entryPoint: 'main' } });
  const bg = device.createBindGroup({ layout: pl.getBindGroupLayout(0), entries: [
    { binding: 0, resource: { buffer: xBuf } }, { binding: 1, resource: { buffer: dBuf } }] });
  dispatchN(pl, bg, N);
  const gpu = await readN(xBuf, N);
  let cpu = [];
  for (let i = 0; i < N; i++) cpu = cpu.concat([aVal(i) * SCALAR]);
  out.scaleGpu = [q4(gpu[0]), q4(gpu[50]), q4(gpu[95])];
  out.scaleCpu = [q4(cpu[0]), q4(cpu[50]), q4(cpu[95])];
}

console.log('__RESULT__ ' + JSON.stringify(out));
